import{QuasiFuchsianGroups}from"./class.min.js";import{GenerateButton}from"/scripts/components/buttons.min.js";import{TextBox}from"/scripts/components/textBoxes.min.js";import{$}from"/scripts/src/main.min.js";export default function(){const e=new QuasiFuchsianGroups({canvas:$("#output-canvas")}),n=new TextBox({element:$("#resolution-input"),name:"Resolution",value:500,minValue:100,maxValue:1e3,onInput:function(){e.resolutionSmall=n.value,e.resolutionLarge=3*n.value,e.wilson.resizeCanvas({width:e.resolutionSmall})}}),t=new TextBox({element:$("#high-resolution-input"),name:"Resolution",value:1500,minValue:500,maxValue:3e3,onEnter:u}),a=new TextBox({element:$("#max-depth-input"),name:"Iterations",value:1e3,minValue:200,maxValue:2e3,onEnter:u}),o=new TextBox({element:$("#max-pixel-brightness-input"),name:"Quality",value:200,minValue:50,maxValue:500,onEnter:u});async function u(){await e.requestHighResFrame(t.value,a.value,o.value),e.wilson.downloadFrame("a-quasi-fuchsian-group.png")}new GenerateButton({element:$("#generate-button"),onClick:u})}